document.addEventListener("DOMContentLoaded", () => {
  // Buscamos específicamente la sección "Sobre el Autor" (id="about").
  // Así evitamos tocar por error el "A.J." del menú (Navbar) o del footer,
  // que también contienen ese texto y antes causaban el reemplazo equivocado.
  const aboutSection = document.getElementById("about");
  if (!aboutSection) {
    console.warn('No se encontró la sección con id="about".');
    return;
  }

  // Dentro de esa sección, buscamos el <span> que dibuja el "A.J." grande
  // (la marca de agua semitransparente). Debe ser un span "hoja" (sin hijos)
  // cuyo texto sea exactamente "A.J.".
  const spans = aboutSection.querySelectorAll("span");
  let target = null;
  for (const span of spans) {
    if (span.children.length === 0 && span.textContent.trim() === "A.J.") {
      target = span;
      break;
    }
  }

  if (!target) {
    console.warn('No se encontró el span "A.J." dentro de la sección About.');
    return;
  }

  const img = document.createElement("img");
  img.src = "https://github.com/Olochile/AJStempleton/raw/main/AJS1.jpg"; // debe estar junto al index.html (o ajusta la ruta)
  img.alt = "AJ";
  img.style.width = "160px";
  img.style.height = "160px";
  img.style.borderRadius = "50%";
  img.style.objectFit = "cover";
  img.style.display = "block";
  img.style.margin = "0 auto";
  img.style.border = "4px solid var(--accent-color, #d4af37)";

  img.onerror = () => {
    console.error(
      'No se pudo cargar "AJS1.jpg". Verifica que el archivo exista y que la ruta sea correcta ' +
      '(revisa la pestaña Network del navegador para ver el error 404).'
    );
  };

  target.replaceWith(img);
});
